def require_full_auth(f):
    """Decorator that requires BOTH password and MFA verification.
    
    This prevents MFA bypass by ensuring that users cannot access
    any protected resource without completing the full authentication flow.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check if user is logged in at all
        if 'username' not in session:
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({'error': 'Authentication required'}), 401
            return redirect(url_for('login_page'))
        
        # CRITICAL: Check MFA verification status
        # This prevents MFA bypass - users MUST complete MFA
        if not session.get('mfa_verified', False):
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({
                    'error': 'MFA verification required',
                    'message': 'Please complete two-factor authentication',
                    'mfa_url': url_for('verify_mfa_page', _external=True)
                }), 403
            return redirect(url_for('verify_mfa_page'))
        
        # Check session integrity
        if not _validate_session_integrity():
            session.clear()
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({'error': 'Session invalid, please re-authenticate'}), 401
            return redirect(url_for('login_page'))
        
        return f(*args, **kwargs)
    return decorated_function


def require_password_auth(f):
    """Decorator that requires at least password authentication.
    Used only for the MFA verification endpoint itself.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({'error': 'Authentication required'}), 401
            return redirect(url_for('login_page'))
        
        # Check that password was verified
        if not session.get('password_verified', False):
            session.clear()
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({'error': 'Authentication required'}), 401
            return redirect(url_for('login_page'))
        
        return f(*args, **kwargs)
    return decorated_function


def _validate_session_integrity():
    """Validate session hasn't been tampered with."""
    required_fields = ['username', 'password_verified', 'mfa_verified', 'login_time', 'session_token']
    for field in required_fields:
        if field not in session:
            return False
    
    # Check session age (max 1 hour)
    if time.time() - session.get('login_time', 0) > 3600:
        return False
    
    # Verify user still exists
    username = session.get('username')
    if username not in users_db:
        return False
    
    return True


def _generate_session_token():
    """Generate a unique session token for integrity checking."""
    return secrets.token_hex(32)


def _rate_limit_check(key, max_attempts=5, window=300):
    """Simple rate limiting for brute force prevention."""
    current_time = time.time()
    
    if key not in pending_mfa:
        pending_mfa[key] = {'attempts': 0, 'first_attempt': current_time, 'locked_until': 0}
    
    record = pending_mfa[key]
    
    # Check if locked out
    if record.get('locked_until', 0) > current_time:
        remaining = int(record['locked_until'] - current_time)
        return False, f'Too many attempts. Try again in {remaining} seconds.'
    
    # Reset window if expired
    if current_time - record.get('first_attempt', 0) > window:
        record['attempts'] = 0
        record['first_attempt'] = current_time
    
    record['attempts'] += 1
    
    if record['attempts'] > max_attempts:
        record['locked_until'] = current_time + window
        return False, f'Too many attempts. Locked for {window} seconds.'
    
    return True, None


def _reset_rate_limit(key):
    """Reset rate limit after successful verification."""
    if key in pending_mfa:
        del pending_mfa[key]


