@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None, qr_code=None, mfa_secret=None)
    
    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    confirm_password = request.form.get('confirm_password', '')
    
    # Validation
    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required.', qr_code=None, mfa_secret=None)
    
    if len(username) < 3 or len(username) > 50:
        return render_template_string(REGISTER_TEMPLATE, error='Username must be 3-50 characters.', qr_code=None, mfa_secret=None)
    
    if len(password) < 8:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 8 characters.', qr_code=None, mfa_secret=None)
    
    if password != confirm_password:
        return render_template_string(REGISTER_TEMPLATE, error='Passwords do not match.', qr_code=None, mfa_secret=None)
    
    if username in users_db:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists.', qr_code=None, mfa_secret=None)
    
    # Generate MFA secret
    mfa_secret = pyotp.random_base32()
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(name=username, issuer_name='SecureApp')
    
    # Generate QR code
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_code_b64 = base64.b64encode(buffer.getvalue()).decode('utf-8')
    
    # Store user
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_secret': mfa_secret,
        'mfa_enabled': True,
        'created_at': time.time()
    }
    
    return render_template_string(REGISTER_TEMPLATE, error=None, qr_code=qr_code_b64, mfa_secret=mfa_secret)


@app.route('/login', methods=['GET', 'POST'])
def login_page():
    if request.method == 'GET':
        # If already fully authenticated, redirect to dashboard
        if session.get('mfa_verified', False):
            return redirect(url_for('dashboard'))
        # If password verified but MFA pending, redirect to MFA
        if session.get('password_verified', False) and not session.get('mfa_verified', False):
            return redirect(url_for('verify_mfa_page'))
        return render_template_string(LOGIN_TEMPLATE, error=None, info=None)
    
    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    
    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required.', info=None), 400
    
    # Rate limiting for login attempts
    rate_key = f'login_{username}'
    allowed, error_msg = _rate_limit_check(rate_key, max_attempts=5, window=300)
    if not allowed:
        return render_template_string(LOGIN_TEMPLATE, error=error_msg, info=None), 429
    
    # Verify credentials
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.', info=None), 401
    
    # Reset login rate limit on successful password
    _reset_rate_limit(rate_key)
    
    # Clear any existing session
    session.clear()
    
    # Set session - password verified but MFA NOT yet verified
    session['username'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False  # CRITICAL: MFA not yet verified
    session['login_time'] = time.time()
    session['session_token'] = _generate_session_token()
    session.permanent = True
    
    # Redirect to MFA verification - user CANNOT access resources until MFA is done
    return redirect(url_for('verify_mfa_page'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
@require_password_auth
def verify_mfa_page():
    # If already MFA verified, go to dashboard
    if session.get('mfa_verified', False):
        return redirect(url_for('dashboard'))
    
    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)
    
    mfa_code = request.form.get('mfa_code', '').strip()
    username = session.get('username')
    
    if not mfa_code:
        return render_template_string(MFA_TEMPLATE, error='Please enter your MFA code.'), 400
    
    # Validate code format
    if not mfa_code.isdigit() or len(mfa_code) != 6:
        return render_template_string(MFA_TEMPLATE, error='Invalid code format. Enter a 6-digit code.'), 400
    
    # Rate limiting for MFA attempts
    rate_key = f'mfa_{username}'
    allowed, error_msg = _rate_limit_check(rate_key, max_attempts=5, window=300)
    if not allowed:
        # On too many MFA failures, invalidate the session entirely
        session.clear()
        return render_template_string(LOGIN_TEMPLATE, 
                                       error='Too many failed MFA attempts. Please login again.', info=None), 429
    
    # Verify TOTP code
    user = users_db.get(username)
    if not user:
        session.clear()
        return redirect(url_for('login_page'))
    
    totp = pyotp.TOTP(user['mfa_secret'])
    
    # valid_window=1 allows for slight time drift (30 seconds before/after)
    if not totp.verify(mfa_code, valid_window=1):
        return render_template_string(MFA_TEMPLATE, error='Invalid MFA code. Please try again.'), 401
    
    # MFA verified successfully
    _reset_rate_limit(rate_key)
    
    # CRITICAL: Set MFA as verified
    session['mfa_verified'] = True
    session['mfa_verified_at'] = time.time()
    
    # Regenerate session token after full authentication
    session['session_token'] = _generate_session_token()
    
    return redirect(url_for('dashboard'))


