# API endpoint for login (JSON-based)
@app.route('/api/login', methods=['POST'])
def api_login():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400
    
    username = data.get('username', '').strip()
    password = data.get('password', '')
    
    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400
    
    # Rate limiting
    rate_key = f'login_{username}'
    allowed, error_msg = _rate_limit_check(rate_key, max_attempts=5, window=300)
    if not allowed:
        return jsonify({'error': error_msg}), 429
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    _reset_rate_limit(rate_key)
    
    session.clear()
    session['username'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False
    session['login_time'] = time.time()
    session['session_token'] = _generate_session_token()
    session.permanent = True
    
    return jsonify({
        'message': 'Password verified. MFA verification required.',
        'mfa_required': True,
        'verify_url': url_for('api_verify_mfa', _external=True),
        'note': 'You MUST complete MFA verification before accessing any protected resources.'
    })


@app.route('/api/verify-mfa', methods=['POST'])
@require_password_auth
def api_verify_mfa():
    if session.get('mfa_verified', False):
        return jsonify({'message': 'Already verified', 'fully_authenticated': True})
    
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400
    
    mfa_code = str(data.get('mfa_code', '')).strip()
    username = session.get('username')
    
    if not mfa_code or not mfa_code.isdigit() or len(mfa_code) != 6:
        return jsonify({'error': 'Valid 6-digit MFA code required'}), 400
    
    rate_key = f'mfa_{username}'
    allowed, error_msg = _rate_limit_check(rate_key, max_attempts=5, window=300)
    if not allowed:
        session.clear()
        return jsonify({'error': 'Too many failed attempts. Session invalidated. Please login again.'}), 429
    
    user = users_db.get(username)
    if not user:
        session.clear()
        return jsonify({'error': 'User not found'}), 401
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code, valid_window=1):
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    _reset_rate_limit(rate_key)
    
    session['mfa_verified'] = True
    session['mfa_verified_at'] = time.time()
    session['session_token'] = _generate_session_token()
    
    return jsonify({
        'message': 'MFA verification successful',
        'fully_authenticated': True
    })


# Security headers middleware
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    response.headers['Pragma'] = 'no-cache'
    return response


# Prevent session fixation by ensuring session cookie settings
@app.before_request
def check_session_security():
    """Additional security checks on every request."""
    # If there's a partial session (password but no MFA), enforce time limit
    if session.get('password_verified') and not session.get('mfa_verified'):
        login_time = session.get('login_time', 0)
        # MFA must be completed within 5 minutes of password verification
        if time.time() - login_time > 300:
            session.clear()
            if request.is_json or request.path.startswith('/api/'):
                pass  # Will be handled by auth decorators
            elif request.endpoint not in ('login_page', 'register', 'index', 'static'):
                return redirect(url_for('login_page'))


